sql:
SELECT COUNT(*) 
FROM list_items 
WHERE mandatory = 1;

SELECT DISTINCT item_id
FROM item_views
ORDER BY item_id ASC;

SELECT interaction_rate
FROM item_statistics
WHERE item_id = 1;

SELECT description
FROM list_items
WHERE item_id = 1;

SELECT COUNT(DISTINCT user_id) AS unique_interacting_users
FROM item_interactions
WHERE item_id = 1;

SELECT content_type, COUNT(item_id) AS item_count
FROM list_items
GROUP BY content_type;

